system_prompt.output_schema:
{
  "is_civil_unrest": true/false,
  "event_type": "Protest / Strike / Blockade / None",
  "confidence_score": 0.00,
  "extraction": {
    "location": "Most specific place named: venue, road/highway, district, city, country (or 'Unknown')",
    "trigger": "Root cause of the unrest (e.g., wage cuts, fuel tariffs, government policy)",
    "impact": "Disruptions caused (e.g., road blocked, classes cancelled, clashes/injuries)"
  },
  "filtering_justification": "One sentence explaining inclusion or exclusion."
}
